package main

import (
	"context"
	_ "embed"
	"fmt"
	"os"
	"runtime"
	"runtime/debug"

	"charm.land/fang/v2"
	"charm.land/lipgloss/v2"
	"github.com/port-experimental/port-cli/internal/commands"
	"github.com/port-experimental/port-cli/internal/output"
	"github.com/port-experimental/port-cli/internal/styles"
	"github.com/spf13/cobra"
)

var (
	version   = "0.1.3"
	buildDate = "unknown"
	commit    = "unknown"
)

func init() {
	// Try to get build info from runtime
	if info, ok := debug.ReadBuildInfo(); ok {
		if version == "dev" {
			// Try to get version from build info
			for _, setting := range info.Settings {
				if setting.Key == "vcs.revision" && commit == "unknown" {
					commit = setting.Value
					if len(commit) > 7 {
						commit = commit[:7]
					}
				}
				if setting.Key == "vcs.time" && buildDate == "unknown" {
					buildDate = setting.Value
				}
			}
		}
	}

	// Set build info in commands package
	commands.SetBuildInfo(commands.BuildInfo{
		Version:   version,
		BuildDate: buildDate,
		Commit:    commit,
		GoVersion: runtime.Version(),
		Platform:  fmt.Sprintf("%s/%s", runtime.GOOS, runtime.GOARCH),
	})
}

//go:embed logo.txt
var logo string

func main() {
	rootCmd := &cobra.Command{
		Use:   "port",
		Short: "Port CLI - Modular command-line interface for Port",
		Long: lipgloss.JoinHorizontal(
			lipgloss.Center,
			logo,
			lipgloss.NewStyle().PaddingLeft(2).Render(
				lipgloss.JoinVertical(
					lipgloss.Left,
					styles.Bold.Render("Port CLI\n"),
					lipgloss.NewStyle().Faint(true).Render("Modular command-line interface for Port")),
			),
		) + "\n\n" +
			`Manage your Port organization with import/export, migration, and API operations.

Credentials can be provided via:
  1. By calling port auth login
  2. CLI flags (--client-id, --client-secret) - highest priority
  3. Environment variables (PORT_CLIENT_ID, PORT_CLIENT_SECRET)
  4. Configuration file (~/.port/config.yaml)`,
		Version: version,
	}

	// Global flags
	var (
		configFile         string
		clientID           string
		clientSecret       string
		apiURL             string
		targetClientID     string
		targetClientSecret string
		targetAPIURL       string
		debug              bool
		noColor            bool
		quiet              bool
		verbose            bool
	)

	rootCmd.PersistentFlags().StringVarP(&configFile, "config", "c", "", "Path to configuration file")
	rootCmd.PersistentFlags().StringVar(&clientID, "client-id", "", "Base org Port API client ID (overrides config/env)")
	rootCmd.PersistentFlags().StringVar(&clientSecret, "client-secret", "", "Base org Port API client secret (overrides config/env)")
	rootCmd.PersistentFlags().StringVar(&apiURL, "api-url", "", "Base org Port API URL (overrides config/env)")
	rootCmd.PersistentFlags().StringVar(&targetClientID, "target-client-id", "", "Target org Port API client ID (overrides config/env)")
	rootCmd.PersistentFlags().StringVar(&targetClientSecret, "target-client-secret", "", "Target org Port API client secret (overrides config/env)")
	rootCmd.PersistentFlags().StringVar(&targetAPIURL, "target-api-url", "", "Target org Port API URL (overrides config/env)")
	rootCmd.PersistentFlags().BoolVarP(&debug, "debug", "d", false, "Enable debug mode")
	rootCmd.PersistentFlags().MarkHidden("debug")
	rootCmd.PersistentFlags().BoolVar(&noColor, "no-color", false, "Disable color output")
	rootCmd.PersistentFlags().BoolVarP(&quiet, "quiet", "q", false, "Suppress non-error output")
	rootCmd.PersistentFlags().BoolVarP(&verbose, "verbose", "v", false, "Enable verbose output")

	// Store global flags in context and initialize color output
	rootCmd.PersistentPreRun = func(cmd *cobra.Command, args []string) {
		// Initialize color output early
		output.Init(noColor)

		// Initialize verbosity
		if quiet {
			output.SetVerbosity(output.QuietLevel)
		} else if verbose {
			output.SetVerbosity(output.VerboseLevel)
		} else {
			output.SetVerbosity(output.NormalLevel)
		}

		cmd.SetContext(commands.WithGlobalFlags(cmd.Context(), commands.GlobalFlags{
			ConfigFile:         configFile,
			ClientID:           clientID,
			ClientSecret:       clientSecret,
			APIURL:             apiURL,
			TargetClientID:     targetClientID,
			TargetClientSecret: targetClientSecret,
			TargetAPIURL:       targetAPIURL,
			Debug:              debug,
			NoColor:            noColor,
			Quiet:              quiet,
			Verbose:            verbose,
		}))
	}

	// Add subcommands
	commands.RegisterAuth(rootCmd)
	commands.RegisterExport(rootCmd)
	commands.RegisterImport(rootCmd)
	commands.RegisterClear(rootCmd)
	commands.RegisterMigrate(rootCmd)
	commands.RegisterCompare(rootCmd)
	commands.RegisterAPI(rootCmd)
	commands.RegisterVersion(rootCmd)
	commands.RegisterConfig(rootCmd)
	commands.RegisterCompletion(rootCmd)
	commands.RegisterSkills(rootCmd)
	commands.RegisterCache(rootCmd)

	themeFunc := fang.WithColorSchemeFunc(func(
		ld lipgloss.LightDarkFunc,
	) fang.ColorScheme {
		def := fang.DefaultColorScheme(ld)
		def.DimmedArgument = ld(lipgloss.Black, lipgloss.White)
		def.Codeblock = ld(lipgloss.Color("#FFFFFF"), lipgloss.Color("#1E1C25"))
		def.Title = lipgloss.Color("#3BB3F6")
		def.Command = lipgloss.Color("#3BB3F6")
		def.Program = ld(lipgloss.Color("#1E1C25"), lipgloss.Color("#FFFFFF"))
		def.Flag = ld(lipgloss.Color("#1E1C25"), lipgloss.Color("#FFFFFF"))
		return def
	})

	if err := fang.Execute(
		context.Background(),
		rootCmd,
		themeFunc,
		fang.WithNotifySignal(os.Interrupt)); err != nil {
		output.Init(false)
		output.SetVerbosity(output.NormalLevel)
		formattedErr := output.FormatError(err)
		if formattedErr != "" {
			output.ErrorPrintf("%s\n", formattedErr)
		} else {
			output.ErrorPrintf("%s: %v\n", output.Error("Error"), err)
		}
		os.Exit(1)
	}
}

.PHONY: help install test clean lint format check build build-release build-all run checksums generate-api

# Default target
help:
	@echo "Port CLI - Makefile Commands"
	@echo ""
	@echo "  make build        - Build the Go binary (dev version)"
	@echo "  make build-release - Build optimized release binary"
	@echo "  make build-all    - Build for all platforms"
	@echo "  make test         - Run all tests"
	@echo "  make test-cov     - Run tests with coverage report"
	@echo "  make lint         - Run linter (golangci-lint)"
	@echo "  make format       - Format code (gofmt)"
	@echo "  make clean        - Clean build artifacts"
	@echo "  make run           - Run the CLI"
	@echo "  make install       - Install the CLI binary"
	@echo "  make checksums    - Generate checksums for binaries"
	@echo "  make generate-api  - Generate OpenAPI client code from spec"

# Version information
VERSION ?= $(shell git describe --tags --always --dirty 2>/dev/null || echo "dev")
BUILD_DATE = $(shell date -u +"%Y-%m-%dT%H:%M:%SZ")
COMMIT = $(shell git rev-parse --short HEAD 2>/dev/null || echo "unknown")

# Build flags
LDFLAGS = -s -w \
	-X 'main.version=$(VERSION)' \
	-X 'main.buildDate=$(BUILD_DATE)' \
	-X 'main.commit=$(COMMIT)'
BUILD_FLAGS = -trimpath -ldflags "$(LDFLAGS)"

# Optimized build flags for smaller binaries
RELEASE_FLAGS = -trimpath -ldflags "$(LDFLAGS)" -buildmode=pie -tags=release

# Build targets
build:
	@echo "Building Port CLI..."
	@mkdir -p bin
	@go build $(BUILD_FLAGS) -o bin/port ./cmd/port
	@echo "Build complete: bin/port"
	@echo "Version: $(VERSION)"

build-release:
	@echo "Building optimized Port CLI release..."
	@mkdir -p bin
	@CGO_ENABLED=0 go build $(RELEASE_FLAGS) -o bin/port ./cmd/port
	@echo "Release build complete: bin/port"
	@ls -lh bin/port
	@echo "Binary size optimization applied (stripped symbols, compressed DWARF)"

build-all:
	@echo "Building Port CLI for all platforms..."
	@echo "Version: $(VERSION)"
	@mkdir -p dist
	@CGO_ENABLED=0 GOOS=linux GOARCH=amd64 go build $(RELEASE_FLAGS) -o dist/port-linux-amd64 ./cmd/port
	@CGO_ENABLED=0 GOOS=linux GOARCH=arm64 go build $(RELEASE_FLAGS) -o dist/port-linux-arm64 ./cmd/port
	@CGO_ENABLED=0 GOOS=darwin GOARCH=amd64 go build $(RELEASE_FLAGS) -o dist/port-darwin-amd64 ./cmd/port
	@CGO_ENABLED=0 GOOS=darwin GOARCH=arm64 go build $(RELEASE_FLAGS) -o dist/port-darwin-arm64 ./cmd/port
	@CGO_ENABLED=0 GOOS=windows GOARCH=amd64 go build $(RELEASE_FLAGS) -o dist/port-windows-amd64.exe ./cmd/port
	@echo "Build complete: dist/"
	@echo "Binaries:"
	@ls -lh dist/

# Test targets
test:
	@echo "Running tests..."
	@go test -v ./...

test-cov:
	@echo "Running tests with coverage..."
	@go test -v -coverprofile=coverage.out ./...
	@go tool cover -html=coverage.out -o coverage.html
	@echo "Coverage report: coverage.html"

# Code quality targets
lint:
	@echo "Running linter..."
	@if command -v golangci-lint >/dev/null 2>&1; then \
		golangci-lint run ./...; \
	else \
		echo "golangci-lint not installed. Install with: go install github.com/golangci/golangci-lint/cmd/golangci-lint@latest"; \
	fi

format:
	@echo "Formatting code..."
	@go fmt ./...
	@if command -v goimports >/dev/null 2>&1; then \
		goimports -w .; \
	else \
	echo "goimports not installed. Install with: go install golang.org/x/tools/cmd/goimports@latest"; \
	fi

check: lint test
	@echo "All quality checks passed!"

# Clean build artifacts
clean:
	@echo "Cleaning build artifacts..."
	@rm -rf bin dist
	@rm -rf coverage.out coverage.html
	@go clean ./...

# Run target
run: build
	@echo "Running Port CLI..."
	@./bin/port --help

# Install target
install: build
	@echo "Installing Port CLI..."
	@mkdir -p /usr/local/bin 2>/dev/null || mkdir -p ~/.local/bin
	@cp bin/port /usr/local/bin/port 2>/dev/null || cp bin/port ~/.local/bin/port
	@echo "Installed: port"

# Development targets
dev-install:
	@echo "Installing CLI in development mode..."
	@go install ./cmd/port

# All quality checks
quality: format lint test
	@echo "All quality checks passed!"

# Complete workflow
all: quality build-release
	@echo "All steps completed successfully!"

# Generate checksums
checksums:
	@echo "Generating checksums..."
	@cd dist && sha256sum port-* > checksums.txt 2>/dev/null || shasum -a 256 port-* > checksums.txt || echo "Checksum generation failed"
	@echo "Checksums: dist/checksums.txt"

# Generate OpenAPI client code
generate-api:
	@echo "Generating OpenAPI client code..."
	@chmod +x scripts/generate-api.sh
	@./scripts/generate-api.sh

